     2→ * X (Twitter) RapidAPI client — twttrapi.p.rapidapi.com
     3→ * Serverless tweet lookup without requiring user OAuth tokens.
     4→ * Used for:
     5→ *   - Agent claim verification (verify tweet contains activation code)
     6→ *   - Quest task verification: post / quote_post (when user has no OAuth token)
     7→ *
     8→ * Env vars:
     9→ *   RAPID_API_KEY                      — RapidAPI key (required)
    10→ *   TWITTER_VERIFY_MENTION_CLAWQUEST   — require @clawquest_ai mention (default: true)
    11→ */
    12→
    13→import { extractTweetId, normaliseHandle } from './x-utils'
    14→
    15→const RAPIDAPI_HOST = 'twttrapi.p.rapidapi.com'
    16→const RAPIDAPI_BASE = `https://${RAPIDAPI_HOST}`
    17→const TIMEOUT_MS = 10_000
    18→
    19→// ── Types ────────────────────────────────────────────────────────
    20→
    21→export interface TweetAuthor {
    22→    screenName: string
    23→    name: string
    24→    id: string
    25→    followersCount: number
    26→    followingCount: number
    27→}
    28→
    29→export interface TweetData {
    30→    id: string
    31→    text: string
    32→    author: TweetAuthor
    33→    mentionedHandles: string[]   // lowercased, no @
    34→    quotedTweetId?: string
    35→}
    36→
    37→export interface TweetVerifyOptions {
    38→    /** If set, tweet must be authored by this handle (case-insensitive, with or without @) */
    39→    expectedAuthorUsername?: string
    40→    /** Code that must appear somewhere in the tweet text */
    41→    verificationCode?: string
    42→    /** Require tweet to mention @clawquest_ai  (default: env TWITTER_VERIFY_MENTION_CLAWQUEST, fallback true) */
    43→    requireMentionClawquest?: boolean
    44→}
    45→
    46→export interface TweetVerifyResult {
    47→    verified: boolean
    48→    reason?: string
    49→    tweet?: TweetData
    50→}
    51→
    52→// ── Internal RapidAPI response shape (twttrapi) ────────────────────
    53→// /tweet-v2 may return tweet_result (internal) or v2-style data+includes.
    54→
    55→interface RapidApiTweetResponse {
    56→    data?: {
    57→        tweet_result?: {
    58→            result?: {
    59→                rest_id?: string
    60→                core?: {
    61→                    user_result?: {
    62→                        result?: {
    63→                            rest_id?: string
    64→                            legacy?: {
    65→                                screen_name?: string
    66→                                name?: string
    67→                                followers_count?: number
    68→                                friends_count?: number
    69→                            }
    70→                        }
    71→                    }
    72→                }
    73→                legacy?: {
    74→                    full_text?: string
    75→                    entities?: {
    76→                        user_mentions?: Array<{ screen_name?: string }>
    77→                    }
    78→                }
    79→                note_tweet?: {
    80→                    note_tweet_results?: {
    81→                        result?: {
    82→                            text?: string
    83→                            entity_set?: {
    84→                                user_mentions?: Array<{ screen_name?: string }>
    85→                            }
    86→                        }
    87→                    }
    88→                }
    89→                quoted_status_id_str?: string
    90→            }
    91→        }
    92→        // v2-style (optional): id, text, author_id, referenced_tweets
    93→        id?: string
    94→        text?: string
    95→        author_id?: string
    96→        referenced_tweets?: Array<{ type?: string; id?: string }>
    97→        entities?: { mentions?: Array<{ username?: string }> }
    98→    }
    99→    includes?: {
   100→        users?: Array<{
   101→            id?: string
   102→            username?: string
   103→            name?: string
   104→            public_metrics?: { followers_count?: number; following_count?: number }
   105→        }>
   106→    }
   107→}
   108→
   109→// ── Helpers ──────────────────────────────────────────────────────
   110→
   111→function rapidApiHeaders(apiKey: string): Record<string, string> {
   112→    return {
   113→        'x-rapidapi-host': RAPIDAPI_HOST,
   114→        'x-rapidapi-key': apiKey,
   115→    }
   116→}
   117→
   118→function parseTweet(id: string, raw: RapidApiTweetResponse): TweetData | null {
   119→    const parsed = parseTweetInternal(id, raw) ?? parseTweetV2Style(id, raw) ?? parseTweetFlexible(id, raw, raw)
   120→    return parsed
   121→}
   122→
   123→function parseTweetInternal(id: string, raw: RapidApiTweetResponse): TweetData | null {
   124→    const result = raw?.data?.tweet_result?.result
   125→    if (!result) return null
   126→
   127→    const authorResult = result.core?.user_result?.result
   128→    const authorLegacy = authorResult?.legacy
   129→    if (!authorLegacy?.screen_name) return null
   130→
   131→    const noteTweet = result.note_tweet?.note_tweet_results?.result
   132→    const text = noteTweet?.text ?? result.legacy?.full_text ?? ''
   133→
   134→    const legacyMentions = result.legacy?.entities?.user_mentions ?? []
   135→    const noteMentions = noteTweet?.entity_set?.user_mentions ?? []
   136→    const mentionedHandles = [
   137→        ...new Set(
   138→            [...legacyMentions, ...noteMentions]
   139→                .map(m => normaliseHandle(m.screen_name ?? ''))
   140→                .filter(Boolean),
   141→        ),
   142→    ]
   143→
   144→    return {
   145→        id,
   146→        text,
   147→        author: {
   148→            screenName: authorLegacy.screen_name,
   149→            name: authorLegacy.name ?? '',
   150→            id: authorResult?.rest_id ?? '',
   151→            followersCount: authorLegacy.followers_count ?? 0,
   152→            followingCount: authorLegacy.friends_count ?? 0,
   153→        },
   154→        mentionedHandles,
   155→        quotedTweetId: result.quoted_status_id_str ?? undefined,
   156→    }
   157→}
   158→
   159→/** Fallback for twttrapi /tweet-v2 when response is Twitter API v2 style (data + includes.users). */
   160→function parseTweetV2Style(id: string, raw: RapidApiTweetResponse): TweetData | null {
   161→    const d = raw?.data
   162→    if (!d?.text && !d?.id) return null
   163→    const authorId = d.author_id
   164→    const users = raw.includes?.users ?? []
   165→    const author = authorId ? users.find(u => u.id === authorId) : users[0]
   166→    if (!author?.username) return null
   167→    const mentionedHandles = (d.entities?.mentions ?? []).map(m => normaliseHandle(m.username ?? '')).filter(Boolean)
   168→    const quoted = d.referenced_tweets?.find(r => r.type === 'quoted')
   169→    return {
   170→        id: d.id ?? id,
   171→        text: d.text ?? '',
   172→        author: {
   173→            screenName: author.username,
   174→            name: author.name ?? '',
   175→            id: author.id ?? '',
   176→            followersCount: author.public_metrics?.followers_count ?? 0,
   177→            followingCount: author.public_metrics?.following_count ?? 0,
   178→        },
   179→        mentionedHandles,
   180→        quotedTweetId: quoted?.id,
   181→    }
   182→}
   183→
   184→/** Last-resort: scan for tweet-like object (text/full_text + author) in nested response. */
   185→function parseTweetFlexible(id: string, raw: unknown, root?: unknown): TweetData | null {
   186→    if (!raw || typeof raw !== 'object') return null
   187→    const rootObj = (root ?? raw) as Record<string, unknown>
   188→    const obj = raw as Record<string, unknown>
   189→    const legacy = obj.legacy as Record<string, unknown> | undefined
   190→    const noteTweet = (obj.note_tweet as { note_tweet_results?: { result?: { text?: string } } })?.note_tweet_results?.result?.text
   191→    const text =
   192→        typeof obj.full_text === 'string' ? obj.full_text
   193→            : typeof obj.text === 'string' ? obj.text
   194→                : typeof legacy?.full_text === 'string' ? legacy.full_text
   195→                    : typeof noteTweet === 'string' ? noteTweet
   196→                        : null
   197→    if (!text) {
   198→        const data = obj.data as Record<string, unknown> | undefined
   199→        if (data && typeof data === 'object') {
   200→            const inner = (data.tweet_result as { result?: Record<string, unknown> })?.result ?? data.result ?? data
   201→            if (inner && typeof inner === 'object') return parseTweetFlexible(id, inner, rootObj)
   202→            return parseTweetFlexible(id, data, rootObj)
   203→        }
   204→        const result = obj.result as Record<string, unknown> | undefined
   205→        if (result && typeof result === 'object') return parseTweetFlexible(id, result, rootObj)
   206→        return null
   207→    }
   208→    let screenName = ''
   209→    let name = ''
   210→    let authorId = ''
   211→    let followersCount = 0
   212→    let followingCount = 0
   213→    if (typeof obj.author_id === 'string') {
   214→        authorId = obj.author_id
   215→        type IncludesUsers = { includes?: { users?: Array<{ id?: string; username?: string; name?: string; public_metrics?: { followers_count?: number; following_count?: number } }> } }
   216→        const rootIncludes = (rootObj as IncludesUsers).includes
   217→        const user = rootIncludes?.users?.find((u: { id?: string }) => u.id === authorId)
   218→        if (user) {
   219→            screenName = (user as { username?: string }).username ?? ''
   220→            name = (user as { name?: string }).name ?? ''
   221→            authorId = (user as { id?: string }).id ?? authorId
   222→            const pm = (user as { public_metrics?: { followers_count?: number; following_count?: number } }).public_metrics
   223→            followersCount = pm?.followers_count ?? 0
   224→            followingCount = pm?.following_count ?? 0
   225→        }
   226→    }
   227→    const core = obj.core as { user_result?: { result?: { legacy?: { screen_name?: string; name?: string; followers_count?: number; friends_count?: number }; rest_id?: string } } } | undefined
   228→    const authorLegacy = core?.user_result?.result?.legacy
   229→    if (authorLegacy && typeof authorLegacy.screen_name === 'string') {
   230→        screenName = authorLegacy.screen_name
   231→        name = String(authorLegacy.name ?? '')
   232→        authorId = core?.user_result?.result?.rest_id ?? authorId
   233→        followersCount = Number(authorLegacy.followers_count ?? 0)
   234→        followingCount = Number(authorLegacy.friends_count ?? 0)
   235→    }
   236→    if (!screenName) return null
   237→    const entities = (obj.entities as { user_mentions?: Array<{ screen_name?: string }> })?.user_mentions ?? (obj.entities as { mentions?: Array<{ username?: string }> })?.mentions
   238→    const mentionedHandles = Array.isArray(entities)
   239→        ? entities.map((m: { screen_name?: string; username?: string }) => normaliseHandle((m as { screen_name?: string }).screen_name ?? (m as { username?: string }).username ?? '')).filter(Boolean)
   240→        : []
   241→    const quoted = (obj.quoted_status_id_str as string) ?? (obj.referenced_tweets as Array<{ type?: string; id?: string }>)?.find(r => r.type === 'quoted')?.id
   242→    return {
   243→        id: typeof obj.rest_id === 'string' ? obj.rest_id : typeof obj.id === 'string' ? obj.id : id,
   244→        text,
   245→        author: { screenName, name, id: authorId, followersCount, followingCount },
   246→        mentionedHandles: [...new Set(mentionedHandles)],
   247→        quotedTweetId: quoted ?? undefined,
   248→    }
   249→}
