   251→// ── Public API ───────────────────────────────────────────────────
   252→
   253→/** Fetch a single tweet by ID. Returns null if not found or API unavailable. */
   254→export async function fetchTweetById(
   255→    tweetId: string,
   256→    apiKey?: string,
   257→): Promise<TweetData | null> {
   258→    const key = apiKey ?? process.env.RAPID_API_KEY ?? ''
   259→    if (!key) return null
   260→
   261→    const url = `${RAPIDAPI_BASE}/tweet-v2?pid=${encodeURIComponent(tweetId)}`
   262→    try {
   263→        const res = await fetch(url, {
   264→            headers: rapidApiHeaders(key),
   265→            signal: AbortSignal.timeout(TIMEOUT_MS),
   266→        })
   267→        if (!res.ok) return null
   268→        const data = await res.json() as RapidApiTweetResponse
   269→        return parseTweet(tweetId, data)
   270→    } catch {
   271→        return null
   272→    }
   273→}
   274→
   275→/** Fetch a tweet from a full URL. Returns null if URL invalid or tweet not found. */
   276→export async function fetchTweetByUrl(
   277→    tweetUrl: string,
   278→    apiKey?: string,
   279→): Promise<TweetData | null> {
   280→    const tweetId = extractTweetId(tweetUrl)
   281→    if (!tweetId) return null
   282→    return fetchTweetById(tweetId, apiKey)
   283→}
   284→
   285→/**
   286→ * Verify a tweet satisfies a set of conditions.
   287→ *
   288→ * Use cases:
   289→ *  - Agent claim: verificationCode = first 8 chars of verificationToken
   290→ *  - Quest post task: verificationCode = undefined, expectedAuthorUsername = user's X handle
   291→ */
   292→export async function verifyTweet(
   293→    tweetUrl: string,
   294→    options: TweetVerifyOptions = {},
   295→): Promise<TweetVerifyResult> {
   296→    const apiKey = process.env.RAPID_API_KEY ?? ''
   297→
   298→    // Resolve requireMentionClawquest: options > env > default true
   299→    const requireMention = options.requireMentionClawquest
   300→        ?? (process.env.TWITTER_VERIFY_MENTION_CLAWQUEST !== 'false')
   301→
   302→    // Step 1: Extract tweet ID
   303→    const tweetId = extractTweetId(tweetUrl)
   304→    if (!tweetId) {
   305→        return { verified: false, reason: 'Invalid Twitter URL format' }
   306→    }
   307→
   308→    if (!apiKey) {
   309→        return { verified: false, reason: 'Twitter verification not configured (missing RAPID_API_KEY)' }
   310→    }
   311→
   312→    // Step 2: Fetch tweet (try multiple endpoints for better compatibility)
   313→    let tweet: TweetData | null = null
   314→    const endpoints = [
   315→        `/tweet-v2?pid=${encodeURIComponent(tweetId)}`,
   316→        `/get-tweet?tweet_id=${encodeURIComponent(tweetId)}`,
   317→    ]
   318→
   319→    let lastError: string | null = null
   320→
   321→    for (const endpoint of endpoints) {
   322→        try {
   323→            const url = `${RAPIDAPI_BASE}${endpoint}`
   324→            const res = await fetch(url, {
   325→                headers: rapidApiHeaders(apiKey),
   326→                signal: AbortSignal.timeout(TIMEOUT_MS),
   327→            })
   328→
   329→            if (res.status === 429) {
   330→                return { verified: false, reason: 'Rate limit exceeded — please try again later' }
   331→            }
   332→
   333→            if (res.status === 402) {
   334→                return { verified: false, reason: 'RapidAPI payment required — your API key may have exceeded its quota or subscription limit' }
   335→            }
   336→
   337→            if (!res.ok) {
   338→                // Try to get error details from response
   339→                let errorDetail = ''
   340→                let errorBody = ''
   341→                try {
   342→                    errorBody = await res.text()
   343→                    if (errorBody) {
   344→                        const parsed = JSON.parse(errorBody)
   345→                        errorDetail = parsed.message || parsed.error || parsed.detail || errorBody.substring(0, 200)
   346→
   347→                        // Check for common RapidAPI error messages
   348→                        if (errorDetail.toLowerCase().includes('quota') ||
   349→                            errorDetail.toLowerCase().includes('credit') ||
   350→                            errorDetail.toLowerCase().includes('subscription')) {
   351→                            return { verified: false, reason: `RapidAPI quota exceeded: ${errorDetail}` }
   352→                        }
   353→                    }
   354→                } catch {
   355→                    errorDetail = `HTTP ${res.status}`
   356→                }
   357→
   358→                // Store error for fallback to next endpoint
   359→                lastError = `Endpoint ${endpoint}: ${res.status} - ${errorDetail || 'Unknown error'}`
   360→
   361→                // If 404, try next endpoint; otherwise return error immediately
   362→                if (res.status === 404) {
   363→                    continue // Try next endpoint
   364→                }
   365→
   366→                if (res.status === 403 || res.status === 401) {
   367→                    return { verified: false, reason: 'Twitter API authentication failed — please check API configuration or subscription status' }
   368→                }
   369→
   370→                // For other errors, try next endpoint if available
   371→                if (endpoint !== endpoints[endpoints.length - 1]) {
   372→                    continue
   373→                }
   374→
   375→                return { verified: false, reason: `Tweet verification failed (${res.status}): ${errorDetail || 'Unknown error'}` }
   376→            }
   377→
   378→            // Success - parse response
   379→            const data = await res.json() as RapidApiTweetResponse
   380→            tweet = parseTweet(tweetId, data)
   381→
   382→            // If successfully parsed, break out of loop
   383→            if (tweet) {
   384→                break
   385→            }
   386→
   387→            // If parse failed, try next endpoint
   388→            lastError = `Failed to parse response from ${endpoint}`
   389→        } catch (err: any) {
   390→            lastError = `Error fetching from ${endpoint}: ${err?.message || 'Unknown error'}`
   391→            // Try next endpoint if available
   392→            if (endpoint !== endpoints[endpoints.length - 1]) {
   393→                continue
   394→            }
   395→
   396→            if (err?.name === 'TimeoutError') {
   397→                return { verified: false, reason: 'Twitter API timeout — please try again' }
   398→            }
   399→            return { verified: false, reason: `Tweet verification error: ${err?.message || 'Unknown error'}` }
   400→        }
   401→    }
   402→
   403→    // If we get here and tweet is still null, all endpoints failed
   404→    if (!tweet) {
   405→        if (lastError?.includes('404')) {
   406→            return { verified: false, reason: `Tweet not found (tweet ID: ${tweetId}) — the tweet may have been deleted, is private, or the URL is invalid. Error: ${lastError}` }
   407→        }
   408→        return { verified: false, reason: `Failed to fetch tweet: ${lastError || 'All endpoints failed'}` }
   409→    }
   410→
   411→    // Step 3a: Check author
   412→    if (options.expectedAuthorUsername) {
   413→        const expected = normaliseHandle(options.expectedAuthorUsername)
   414→        const actual = normaliseHandle(tweet.author.screenName)
   415→        if (actual !== expected) {
   416→            return {
   417→                verified: false,
   418→                reason: 'Tweet must be posted by your Twitter account',
   419→                tweet,
   420→            }
   421→        }
   422→    }
   423→
   424→    // Step 3b: Check @clawquest_ai mention
   425→    if (requireMention) {
   426→        const hasMention =
   427→            tweet.mentionedHandles.includes('clawquest_ai') ||
   428→            tweet.text.toLowerCase().includes('@clawquest_ai')
   429→
   430→        if (!hasMention) {
   431→            return {
   432→                verified: false,
   433→                reason: 'Tweet must mention @clawquest',
   434→                tweet,
   435→            }
   436→        }
   437→    }
   438→
   439→    // Step 3c: Check verification code
   440→    if (options.verificationCode && !tweet.text.includes(options.verificationCode)) {
   441→        return {
   442→            verified: false,
   443→            reason: 'Tweet does not contain verification code',
   444→            tweet,
   445→        }
   446→    }
   447→
   448→    return { verified: true, tweet }
   449→}
