   451→// ── User-action verification via RapidAPI ────────────────────────
   452→// Used to verify like_post / repost / follow_account without OAuth tokens.
   453→// Identifies users by xHandle (screen_name) rather than xId.
   454→
   455→interface RapidApiUserListResponse {
   456→    data?: {
   457→        users?: Array<{
   458→            result?: {
   459→                rest_id?: string
   460→                legacy?: { screen_name?: string }
   461→            }
   462→        }>
   463→    }
   464→    next_cursor?: string
   465→}
   466→
   467→/** Extract screen_names from deeply-nested or flat user-list RapidAPI responses. */
   468→function extractScreenNames(data: unknown): string[] {
   469→    if (!data || typeof data !== 'object') return []
   470→    const names: string[] = []
   471→    // Flat format: { data: { users: [{ result: { legacy: { screen_name } } }] } }
   472→    const flat = (data as RapidApiUserListResponse)?.data?.users ?? []
   473→    for (const u of flat) {
   474→        const sn = u.result?.legacy?.screen_name
   475→        if (sn) names.push(normaliseHandle(sn))
   476→    }
   477→    // If flat format found users, return
   478→    if (names.length > 0) return names
   479→    // Fallback: recursively scan for screen_name strings (handles deeply nested formats)
   480→    function scan(obj: unknown): void {
   481→        if (!obj || typeof obj !== 'object') return
   482→        if (Array.isArray(obj)) { obj.forEach(scan); return }
   483→        const o = obj as Record<string, unknown>
   484→        if (typeof o['screen_name'] === 'string') names.push(normaliseHandle(o['screen_name'] as string))
   485→        for (const v of Object.values(o)) scan(v)
   486→    }
   487→    scan(data)
   488→    return names
   489→}
   490→
   491→
   492→/** Extract pagination cursor from RapidAPI user-list responses. */
   493→function extractNextCursor(data: unknown): string | null {
   494→    if (!data || typeof data !== 'object') return null
   495→    const flat = (data as RapidApiUserListResponse).next_cursor
   496→    if (flat) return flat
   497→    // Scan for cursor strings in nested formats
   498→    function findCursor(obj: unknown): string | null {
   499→        if (!obj || typeof obj !== 'object') return null
   500→        if (Array.isArray(obj)) {
   501→            for (const item of obj) { const c = findCursor(item); if (c) return c }
   502→            return null
   503→        }
   504→        const o = obj as Record<string, unknown>
   505→        for (const [k, v] of Object.entries(o)) {
   506→            if ((k === 'next_cursor' || k === 'cursor_bottom' || k === 'cursor') && typeof v === 'string' && v) return v
   507→            const c = findCursor(v); if (c) return c
   508→        }
   509→        return null
   510→    }
   511→    return findCursor(data)
   512→}
   513→
   514→/** Recursively extract tweet id_str values from any twttrapi response format. */
   515→function extractTweetIds(data: unknown): string[] {
   516→    const ids: string[] = []
   517→    function scan(obj: unknown): void {
   518→        if (!obj || typeof obj !== 'object') return
   519→        if (Array.isArray(obj)) { obj.forEach(scan); return }
   520→        const o = obj as Record<string, unknown>
   521→        if (typeof o['id_str'] === 'string' && /^\d+$/.test(o['id_str'] as string)) ids.push(o['id_str'] as string)
   522→        for (const v of Object.values(o)) scan(v)
   523→    }
   524→    scan(data)
   525→    return ids
   526→}
