   528→/**
   529→ * Check if a user (identified by xId) liked a given tweet.
   530→ * Uses twttrapi GET /user/likes?user_id={xId}. Paginates up to 5 pages (~500 likes max). Returns null on API error.
   531→ */
   532→export async function checkUserLikedTweet(
   533→    tweetId: string, xId: string, apiKey?: string,
   534→): Promise<boolean | null> {
   535→    const key = apiKey ?? process.env.RAPID_API_KEY ?? ''
   536→    if (!key) return null
   537→    let cursor = ''
   538→    for (let page = 0; page < 5; page++) {
   539→        try {
   540→            const url = `${RAPIDAPI_BASE}/user/likes?user_id=${encodeURIComponent(xId)}&count=100${cursor ? `&cursor=${encodeURIComponent(cursor)}` : ''}`
   541→            const res = await fetch(url, { headers: rapidApiHeaders(key), signal: AbortSignal.timeout(TIMEOUT_MS) })
   542→            if (!res.ok) return null
   543→            const data = await res.json() as unknown
   544→            const ids = extractTweetIds(data)
   545→            if (ids.includes(tweetId)) return true
   546→            const next = extractNextCursor(data)
   547→            if (!next || ids.length === 0) return false
   548→            cursor = next
   549→        } catch {
   550→            return null
   551→        }
   552→    }
   553→    return false
   554→}
